'from flask import Flask\nfrom flask_sqlalchemy import SQLAlchemy\n\ndb = SQLAlchemy()\n\ndef create_app():\n    app = Flask(__name__)\n    app.config[\'SQLALCHEMY_DATABASE_URI\'] = \'sqlite:///site.db\'  # Example database URI\n    app.config[\'SQLALCHEMY_TRACK_MODIFICATIONS\'] = False\n    \ndb.init_app(app)\n\n    with app.app_context():\n        db.create_all()  # Create database tables\n        seed_data()  # Seed data\n\n    return app\n\ndef seed_data():\n    # Example seeding logic\n    from models import User, Group  # Assuming you have User and Group models\n\n    admin_user = User(username=\'admin\', password=\'admin\', role=\'admin\')\n    db.session.add(admin_user)\n    db.session.commit()\n\n    # Add more data as needed'